                    if (properties.SequenceEqual(State340)) return new Block.Water(true, 6, true);
                    if (properties.SequenceEqual(State341)) return new Block.Water(true, 5, true);
                    if (properties.SequenceEqual(State342)) return new Block.Water(true, 4, true);
                    if (properties.SequenceEqual(State343)) return new Block.Water(true, 3, true);
                    if (properties.SequenceEqual(State344)) return new Block.Water(true, 2, true);
                    if (properties.SequenceEqual(State345)) return new Block.Water(true, 1, true);
                    break;
            }
            return new EncodedLiquid(identifier, properties.ToArray());
        }

        private sealed record EncodedBlock(string Identifier, byte[] Properties) : World.Block;
        private sealed record EncodedLiquid(string Identifier, byte[] Properties) : World.Liquid
        {
            public string LiquidType() => throw new InvalidOperationException("Opaque liquid type was not transported by the host.");
        }
    }
}
